  erros.push('Código de Barras deve ter 48 dígitos (tem ' + codigoBarras.length + ')');
  validacao_ok = false;
}

// Validação 3: Deve começar com 8
if (codigoBarras && !codigoBarras.startsWith('8')) {
  erros.push('Código de Barras de Concessionária deve começar com 8');
  validacao_ok = false;
}

// Validação 4: Módulo 10 ou 11 (FEBRABAN) e extração de valor
if (codigoBarras && codigoBarras.length === 48) {
  const tipoValor = codigoBarras[2];

  // Extrair valor (posições 4-14, 11 dígitos)
  const valorCentavos = parseInt(codigoBarras.substring(4, 15));
  if (valorCentavos > 0) {
    valorExtraido = valorCentavos / 100;
  }

  function modulo10(bloco) {
    let soma = 0;
    let peso = 2;
    for (let i = bloco.length - 1; i >= 0; i--) {
      let resultado = parseInt(bloco[i]) * peso;
      soma += resultado >= 10 ? Math.floor(resultado / 10) + (resultado % 10) : resultado;
      peso = peso === 2 ? 1 : 2;
    }
    let resto = soma % 10;
    return resto === 0 ? 0 : 10 - resto;
  }

  function modulo11(bloco) {
    let soma = 0;
    let peso = 2;
    for (let i = bloco.length - 1; i >= 0; i--) {
      soma += parseInt(bloco[i]) * peso;
      peso = peso === 9 ? 2 : peso + 1;
    }
    let resto = soma % 11;
    if (resto === 0 || resto === 1) return 0;
    if (resto === 10) return 1;
    return 11 - resto;
  }

