    validacao_ok: validacao_ok,
    validacao_erros: erros
  }
};

const dados = $json;
const forma = (dados["Forma de Pagamento"] || '').toLowerCase();
let faltamDados = false;
let erros = [];

if (forma === 'ted') {
  if (!dados['CNPJ/CPF'] || !dados['CNPJ/CPF'].toString().trim()) erros.push('CNPJ/CPF');
  if (!dados.Banco) erros.push('Banco');
  if (!dados['Agência']) erros.push('Agência');
  if (!dados.Conta) erros.push('Conta');
  if (!dados['Tipo Conta']) erros.push('Tipo Conta');
  if (!dados.Nome || !dados.Nome.toString().trim()) erros.push('Nome');
  if (!dados.Valor) erros.push('Valor');
  if (!dados.Vencimento) erros.push('Vencimento');
} else if (forma === 'boleto') {
  if (!dados['CNPJ/CPF'] || !dados['CNPJ/CPF'].toString().trim()) erros.push('CNPJ/CPF');
  if (!dados.Nome || !dados.Nome.toString().trim()) erros.push('Nome');
  if (!dados['Código de Barras'] || !dados['Código de Barras'].toString().trim()) erros.push('Código de Barras');
}

faltamDados = erros.length > 0;

return {
  json: {
    ...dados,
    faltam_dados: faltamDados,
    campos_faltando: erros
  }
};
